370	/// @brief Apply a general Pauli rotation, takes a qubit register and the size
371	/// must be equal to the Pauli word length.
372	template <typename QubitRange>
373	  requires(std::ranges::range<QubitRange>)
374	void exp_pauli(double theta, QubitRange &&qubits, const char *pauliWord) {
375	  std::vector<QuditInfo> quditInfos;
376	  std::transform(qubits.begin(), qubits.end(), std::back_inserter(quditInfos),
377	                 [](auto &q) { return cudaq::qubitToQuditInfo(q); });
378	  // FIXME: it would be cleaner if we just kept it as a pauli word here
379	  getExecutionManager()->apply("exp_pauli", {theta}, {}, quditInfos, false,
380	                               spin_op::from_word(pauliWord));
381	}
