384	/// must be equal to the Pauli word length.
385	template <typename QubitRange>
386	  requires(std::ranges::range<QubitRange>)
387	void exp_pauli(double theta, QubitRange &&qubits,
388	               const cudaq::pauli_word &pauliWord) {
389	  exp_pauli(theta, qubits, pauliWord.str().c_str());
390	}
