426	// `mz`/`mx`/`my` are `__qpu__`-only entry points. In MLIR mode the bridge
427	// intercepts every call to these functions inside a `__qpu__` kernel and emits
428	// the corresponding `quake.{mz, mx, my}` op directly, so the inline body never
429	// runs in a built kernel; we therefore throw so host-scope misuse
430	// fails loudly instead of returning a meaningless value.
431	namespace detail {
432	inline constexpr const char *kQpuOnlyHostScopeError =
433	    "Not allowed on host code; usable only inside a `__qpu__` kernel.";
434	}
435	
436	/// @brief Measure an individual qubit, return 0,1 as `bool`
437	inline measure_result mz(qubit &q) {
438	#ifdef CUDAQ_LIBRARY_MODE
439	  return getExecutionManager()->measure(QuditInfo{q.n_levels(), q.id()});
440	#else
441	  (void)q;
442	  throw std::runtime_error(detail::kQpuOnlyHostScopeError);
443	#endif
444	}
445	
446	/// @brief Measure an individual qubit in `x` basis, return 0,1 as `bool`
447	inline measure_result mx(qubit &q) {
448	#ifdef CUDAQ_LIBRARY_MODE
449	  h(q);
450	  return getExecutionManager()->measure(QuditInfo{q.n_levels(), q.id()});
451	#else
452	  (void)q;
453	  throw std::runtime_error(detail::kQpuOnlyHostScopeError);
454	#endif
455	}
